    fields.push({ field: 'name', message: 'Name is required (min 2 characters)' });
  }
  if (!isValidEmail(email)) {
    fields.push({ field: 'email', message: 'A valid email address is required' });
  }
  if (!turnstileToken) {
    fields.push({ field: 'turnstileToken', message: 'Captcha verification is required' });
  }

  if (fields.length > 0) {
    return jsonError(400, 'Please fix the errors below', fields);
  }

  // --- Turnstile verification ---
  const turnstileOk = await verifyTurnstile(turnstileToken);
  if (!turnstileOk) {
    return jsonError(403, 'Captcha verification failed. Please try again.');
  }

  // --- Send email ---
  const to = import.meta.env.CONTACT_EMAIL || 'onboarding@resend.dev';
  const ok = await sendEmail({
    to,
    subject: `New Connection Request from ${name}`,
    replyTo: email,
    html: `
      <h2>New Connection Request</h2>
      <p><strong>Name:</strong> ${escapeHtml(name)}</p>
      <p><strong>Email:</strong> ${escapeHtml(email)}</p>
      ${phone ? `<p><strong>Phone:</strong> ${escapeHtml(phone)}</p>` : ''}
      ${interests ? `<p><strong>Interests:</strong> ${escapeHtml(interests)}</p>` : ''}
      ${message ? `<p><strong>Message:</strong> ${escapeHtml(message).replace(/\n/g, '<br>')}</p>` : ''}
    `,
  });

  if (!ok) {
    return jsonError(500, 'Unable to submit your connection request right now. Please try again later.');
  }

  return jsonSuccess('Thank you for reaching out! We'll be in touch soon.');
};

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

